1	export type Cell = [number, number];
2	
3	const NEIGHBOR_OFFSETS: ReadonlyArray<[number, number]> = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [0, -1],           [0, 1],
6	  [1, -1],  [1, 0],  [1, 1],
7	];
8	
9	export function nextGeneration(cells: Cell[]): Cell[] {
10	  const isLive = (x: number, y: number): boolean =>
11	    cells.some(([cx, cy]) => cx === x && cy === y);
12	
13	  const countLiveNeighbors = (x: number, y: number): number =>
14	    NEIGHBOR_OFFSETS.filter(([dx, dy]) => isLive(x + dx, y + dy)).length;
15	
16	  const survives = (neighbors: number): boolean =>
17	    neighbors === 2 || neighbors === 3;
18	
19	  const neighborsOf = ([x, y]: Cell): Cell[] =>
20	    NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);
21	
22	  const uniqueCells = (all: Cell[]): Cell[] =>
23	    Array.from(new Map(all.map((c) => [`${c[0]},${c[1]}`, c])).values());
24	
25	  const survivors = cells.filter(([x, y]) => survives(countLiveNeighbors(x, y)));
26	
27	  const deadNeighbors = uniqueCells(cells.flatMap(neighborsOf))
28	    .filter(([x, y]) => !isLive(x, y));
29	
30	  const births = deadNeighbors.filter(([x, y]) => countLiveNeighbors(x, y) === 3);
31	
32	  return [...survivors, ...births];
33	}
